// =============================================================================
// Lookup Functions
// =============================================================================

/// Find package pin by name (e.g. "U22").
pub fn findPackagePin(pin_name: []const u8) ?PackagePin {
    for (package_pins) |pin| {
        if (std.mem.eql(u8, pin.pin, pin_name)) return pin;
    }
    return null;
}

/// Find CLB tile at (x, y).
pub fn findClbTile(x: u8, y: u8) ?ClbTile {
    for (clb_tiles) |tile| {
        if (tile.x == x and tile.y == y) return tile;
    }
    return null;
}

/// Find INT tile at (x, y).
pub fn findIntTile(x: u8, y: u8) ?IntTile {
    for (int_tiles) |tile| {
        if (tile.x == x and tile.y == y) return tile;
    }
    return null;
}

/// Find IOB tile containing a given IOB site Y.
pub fn findIobBySiteY(site_y: u16) ?IobTile {
    for (iob_tiles) |tile| {
        if (tile.site0) |s0| {
            if (s0 == site_y) return tile;
        }
        if (tile.site1) |s1| {
            if (s1 == site_y) return tile;
        }
    }
    return null;
}

/// Get tile type name string for FASM output.
pub fn tileTypeName(tt: TileType) []const u8 {
    return switch (tt) {
        .clbll_l => "CLBLL_L",
        .clbll_r => "CLBLL_R",
        .clblm_l => "CLBLM_L",
        .clblm_r => "CLBLM_R",
        .liob33 => "LIOB33",
        .liob33_sing => "LIOB33_SING",
        .riob33 => "RIOB33",
        .riob33_sing => "RIOB33_SING",
        .int_l => "INT_L",
        .int_r => "INT_R",
        .clk_bufg_bot_r => "CLK_BUFG_BOT_R",
        .clk_bufg_top_r => "CLK_BUFG_TOP_R",
        .clk_bufg_rebuf => "CLK_BUFG_REBUF",
        .clk_hrow_bot_r => "CLK_HROW_BOT_R",
        .clk_hrow_top_r => "CLK_HROW_TOP_R",
        .hclk_l => "HCLK_L",
        .hclk_r => "HCLK_R",
        .hclk_cmt => "HCLK_CMT",
        .hclk_cmt_l => "HCLK_CMT_L",
        .lioi3 => "LIOI3",
        .lioi3_sing => "LIOI3_SING",
        .lioi3_tbytesrc => "LIOI3_TBYTESRC",
        .lioi3_tbyteterm => "LIOI3_TBYTETERM",
        .rioi3 => "RIOI3",
        .rioi3_sing => "RIOI3_SING",
        .rioi3_tbytesrc => "RIOI3_TBYTESRC",
        .rioi3_tbyteterm => "RIOI3_TBYTETERM",
    };
}

/// Check if tile type is a left-side tile.
pub fn isLeftTile(tt: TileType) bool {
    return switch (tt) {
        .clbll_l, .clblm_l, .int_l, .liob33, .liob33_sing, .hclk_l, .lioi3, .lioi3_sing, .lioi3_tbytesrc, .lioi3_tbyteterm => true,
        else => false,
    };
}

/// Find an IOB tile and get the absolute site Y for a given tile coordinate and site index.
/// bel_index: 0 for site0 (lower), 1 for site1 (upper)
/// Returns the absolute IOB site Y (e.g., 51 for IOB_X0Y51) or null if not found.
pub fn findIobTile(tile_x: u16, tile_y: u16, bel_index: u16) ?u16 {
    for (iob_tiles) |tile| {
        if (tile.x == tile_x and tile.y == tile_y) {
            return if (bel_index == 0) tile.site0 else tile.site1;
        }
    }
    return null;
}

